#!/usr/bin/env python3
"""iteration-1 の目視レビュー用 静的HTMLを生成する（サーバ不要・1ファイル完結）。

各 eval について: プロンプト / 観点チェックリスト / before(fixture)→after(出力) の
ファイル単位 diff / エージェントの作業報告 を1画面にまとめる。
"""
import html
import json
import sys
from difflib import unified_diff
from pathlib import Path

WS = Path(__file__).resolve().parent.parent  # document-harness-workspace
FIX = WS / "fixtures"
IT = WS / "iteration-1"

# (見出し, スキル, eval_name, fixture_dir, output_repo, report) を evals から組み立てる
MANIFEST = [
    {
        "skill": "1natsu-document-harness",
        "evals_json": WS.parent / "1natsu-document-harness" / "evals" / "evals.json",
        "rows": [
            {"id": 1, "fixture": FIX / "fixture-a-init",
             "out": IT / "eval-1-harness-init" / "with_skill" / "repo",
             "report": IT / "eval-1-harness-init" / "with_skill" / "agent-report.md"},
            {"id": 2, "fixture": FIX / "fixture-b-sync",
             "out": IT / "eval-2-harness-sync" / "with_skill" / "repo",
             "report": IT / "eval-2-harness-sync" / "with_skill" / "agent-report.md"},
        ],
    },
    {
        "skill": "1natsu-document-harness-audit",
        "evals_json": WS.parent / "1natsu-document-harness-audit" / "evals" / "evals.json",
        "rows": [
            {"id": 1, "fixture": FIX / "fixture-c-audit",
             "out": IT / "eval-3-audit" / "with_skill" / "repo",
             "report": IT / "eval-3-audit" / "with_skill" / "agent-report.md"},
        ],
    },
]


def list_files(root: Path):
    return {
        str(p.relative_to(root)): p
        for p in sorted(root.rglob("*"))
        if p.is_file()
    }


def read(p: Path):
    try:
        return p.read_text(encoding="utf-8")
    except Exception:
        return "(binary or unreadable)"


def diff_block(rel, before_text, after_text, status):
    if status == "NEW":
        before_lines = []
        after_lines = after_text.splitlines()
    elif status == "DELETED":
        before_lines = before_text.splitlines()
        after_lines = []
    else:
        before_lines = before_text.splitlines()
        after_lines = after_text.splitlines()
    rows = []
    for line in unified_diff(before_lines, after_lines, lineterm="", n=3):
        e = html.escape(line)
        if line.startswith("+++") or line.startswith("---"):
            cls = "meta"
        elif line.startswith("@@"):
            cls = "hunk"
        elif line.startswith("+"):
            cls = "add"
        elif line.startswith("-"):
            cls = "del"
        else:
            cls = "ctx"
        rows.append(f'<div class="line {cls}">{e or "&nbsp;"}</div>')
    badge = {"NEW": "新規", "DELETED": "削除", "MODIFIED": "変更"}[status]
    bcls = {"NEW": "b-new", "DELETED": "b-del", "MODIFIED": "b-mod"}[status]
    return (
        f'<div class="file"><div class="fhead"><span class="badge {bcls}">{badge}</span>'
        f'<code>{html.escape(rel)}</code></div><div class="diff">{"".join(rows)}</div></div>'
    )


def render_eval(skill, ev, row):
    fixture, out = row["fixture"], row["out"]
    fb, of = list_files(fixture), list_files(out)
    blocks = []
    for rel in sorted(set(fb) | set(of)):
        if rel in fb and rel not in of:
            blocks.append(diff_block(rel, read(fb[rel]), "", "DELETED"))
        elif rel not in fb and rel in of:
            blocks.append(diff_block(rel, "", read(of[rel]), "NEW"))
        else:
            bt, at = read(fb[rel]), read(of[rel])
            if bt != at:
                blocks.append(diff_block(rel, bt, at, "MODIFIED"))
    if not blocks:
        blocks.append('<p class="nochange">（差分なし）</p>')
    assertions = "".join(
        f"<li>{html.escape(a)}</li>" for a in ev.get("assertions", [])
    )
    report = read(row["report"]) if row["report"].exists() else "(no report)"
    return f"""
    <section class="eval">
      <h3>{html.escape(skill)} / eval {ev['id']}: {html.escape(ev.get('name',''))}</h3>
      <details open><summary>プロンプト（ユーザー依頼）</summary>
        <blockquote>{html.escape(ev.get('prompt','')).replace(chr(10),'<br>')}</blockquote>
      </details>
      <details><summary>観点チェックリスト（このevalで満たしたい挙動）</summary>
        <ul class="assertions">{assertions}</ul>
      </details>
      <h4>before(fixture) → after(出力) の差分</h4>
      {''.join(blocks)}
      <details><summary>エージェントの作業報告（蒸留の判断根拠）</summary>
        <pre class="report">{html.escape(report)}</pre>
      </details>
    </section>
    """


def main():
    sections = []
    for grp in MANIFEST:
        evals = json.loads(read(grp["evals_json"]))["evals"]
        ev_by_id = {e["id"]: e for e in evals}
        for row in grp["rows"]:
            sections.append(render_eval(grp["skill"], ev_by_id[row["id"]], row))
    body = "\n".join(sections)
    css = """
    body{font-family:-apple-system,BlinkMacSystemFont,'Hiragino Sans','Segoe UI',sans-serif;
      max-width:1000px;margin:0 auto;padding:24px;color:#1a1a1a;line-height:1.6}
    h1{border-bottom:2px solid #333;padding-bottom:8px}
    h2{margin-top:40px}
    .eval{border:1px solid #ddd;border-radius:8px;padding:16px 20px;margin:24px 0;background:#fafafa}
    .eval h3{margin-top:0;color:#0a4}
    blockquote{background:#fff;border-left:4px solid #88a;margin:8px 0;padding:8px 14px;white-space:pre-wrap}
    summary{cursor:pointer;font-weight:600;margin:8px 0}
    .assertions li{margin:4px 0}
    .file{margin:14px 0;border:1px solid #ccc;border-radius:6px;overflow:hidden}
    .fhead{background:#eee;padding:6px 10px;font-size:14px}
    .badge{display:inline-block;padding:1px 8px;border-radius:10px;color:#fff;font-size:12px;margin-right:8px}
    .b-new{background:#0a7}.b-mod{background:#d80}.b-del{background:#c33}
    .diff{font-family:ui-monospace,Menlo,Consolas,monospace;font-size:13px;background:#fff;overflow-x:auto}
    .line{padding:0 10px;white-space:pre}
    .add{background:#e6ffed;color:#064}
    .del{background:#ffeef0;color:#900}
    .hunk{background:#f0f0ff;color:#66a}
    .meta{color:#999}
    .ctx{color:#444}
    .report{background:#fff;border:1px solid #ddd;padding:12px;white-space:pre-wrap;font-size:13px;max-height:480px;overflow:auto}
    .nochange{color:#888}
    .intro{background:#fffbe6;border:1px solid #e8d98a;border-radius:6px;padding:12px 16px}
    """
    out_html = f"""<!doctype html><html lang="ja"><head><meta charset="utf-8">
    <title>document-harness 改善 iteration-1 レビュー</title><style>{css}</style></head>
    <body>
    <h1>document-harness / audit 改善 — iteration-1 目視レビュー</h1>
    <div class="intro">
      <b>見方:</b> 各 eval は「改善版スキルを fixture（小さな実 repo）の上で実走させた結果」。
      <b>左赤=変更前(fixture) / 緑=出力後</b>の差分を見て、<b>仕様への蒸留が適切か</b>を確認してください。
      観点: ①ルールが機構名を持たずポリシーに徹しているか ②機構/ライブラリは docs の理由に回っているか
      ③env名など外部契約面だけ名指しされ、内部変数名・シグネチャは転記されていないか
      ④（audit）コード乖離が裏取りで直っているか・過剰検出していないか。
    </div>
    {body}
    </body></html>"""
    out_path = WS / "review" / "iteration-1-review.html"
    out_path.write_text(out_html, encoding="utf-8")
    print(str(out_path))


if __name__ == "__main__":
    sys.exit(main())

