             "out": IT / "eval-3-audit" / "with_skill" / "repo",
             "report": IT / "eval-3-audit" / "with_skill" / "agent-report.md"},
        ],
    },
]


def list_files(root: Path):
    return {
        str(p.relative_to(root)): p
        for p in sorted(root.rglob("*"))
        if p.is_file()
    }


def read(p: Path):
    try:
        return p.read_text(encoding="utf-8")
    except Exception:
        return "(binary or unreadable)"


def diff_block(rel, before_text, after_text, status):
    if status == "NEW":
        before_lines = []
        after_lines = after_text.splitlines()
    elif status == "DELETED":
        before_lines = before_text.splitlines()
        after_lines = []
    else:
        before_lines = before_text.splitlines()
        after_lines = after_text.splitlines()
    rows = []
    for line in unified_diff(before_lines, after_lines, lineterm="", n=3):
        e = html.escape(line)
        if line.startswith("+++") or line.startswith("---"):
            cls = "meta"
        elif line.startswith("@@"):
            cls = "hunk"
        elif line.startswith("+"):
            cls = "add"
        elif line.startswith("-"):
            cls = "del"
        else:
            cls = "ctx"
        rows.append(f'<div class="line {cls}">{e or "&nbsp;"}</div>')
    badge = {"NEW": "新規", "DELETED": "削除", "MODIFIED": "変更"}[status]
    bcls = {"NEW": "b-new", "DELETED": "b-del", "MODIFIED": "b-mod"}[status]
    return (
        f'<div class="file"><div class="fhead"><span class="badge {bcls}">{badge}</span>'
        f'<code>{html.escape(rel)}</code></div><div class="diff">{"".join(rows)}</div></div>'
    )


def render_eval(skill, ev, row):
    fixture, out = row["fixture"], row["out"]
    fb, of = list_files(fixture), list_files(out)
    blocks = []
    for rel in sorted(set(fb) | set(of)):
        if rel in fb and rel not in of:
            blocks.append(diff_block(rel, read(fb[rel]), "", "DELETED"))
        elif rel not in fb and rel in of:
            blocks.append(diff_block(rel, "", read(of[rel]), "NEW"))
        else:
            bt, at = read(fb[rel]), read(of[rel])
            if bt != at:
                blocks.append(diff_block(rel, bt, at, "MODIFIED"))
    if not blocks:
        blocks.append('<p class="nochange">（差分なし）</p>')
    assertions = "".join(
        f"<li>{html.escape(a)}</li>" for a in ev.get("assertions", [])
    )
    report = read(row["report"]) if row["report"].exists() else "(no report)"
    return f"""
    <section class="eval">
      <h3>{html.escape(skill)} / eval {ev['id']}: {html.escape(ev.get('name',''))}</h3>
      <details open><summary>プロンプト（ユーザー依頼）</summary>
        <blockquote>{html.escape(ev.get('prompt','')).replace(chr(10),'<br>')}</blockquote>
      </details>
      <details><summary>観点チェックリスト（このevalで満たしたい挙動）</summary>
        <ul class="assertions">{assertions}</ul>
      </details>
      <h4>before(fixture) → after(出力) の差分</h4>
      {''.join(blocks)}
      <details><summary>エージェントの作業報告（蒸留の判断根拠）</summary>
        <pre class="report">{html.escape(report)}</pre>
      </details>
    </section>
    """


